@code {
    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private List<string> allChannels = new();
    private bool isLoading = true;
    private bool isSaving;
    private string? successMessage;

    protected override async Task OnInitializedAsync()
    {
        isLoading = true;
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        allChannels = prefs.MutedChannels.Count > 0
            ? prefs.MutedChannels
            : ["general", "announcements", "random", "engineering", "design"];
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        isLoading = false;
    }

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        isSaving = true;
        successMessage = null;
        var prefs = new NotificationPrefs(
            emailNotifications, pushNotifications, weeklyDigest,
            mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        successMessage = "Notification preferences saved!";
        isSaving = false;
    }
}

