@code {
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();
    private ActiveSession? sessionToRevoke;
    private bool isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        isLoading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = settings.Sessions;
        isLoading = false;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
        sessions.Remove(sessionToRevoke);
        sessionToRevoke = null;
    }
}

