         role="button" @onclick="() => isExpanded = !isExpanded">
        <span>Change Password</span>
        <span>@(isExpanded ? "▲" : "▼")</span>
    </div>
    @if (isExpanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success">@successMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@isUpdating">
                @if (isUpdating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    private bool isExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? errorMessage;
    private string? successMessage;
    private bool isUpdating;

    private async Task UpdatePassword()
    {
        errorMessage = null;
        successMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        if (newPassword.Length < 8)
        {
            errorMessage = "New password must be at least 8 characters.";
            return;
        }

        isUpdating = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            successMessage = "Password updated successfully!";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            isUpdating = false;
        }
    }
}
"}

{"path": "/tmp/sv-cc4084934c2743f98203fbf80f935e83/Components/Pages/Settings/SecuritySection.razor", "file_text": "@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security</h3>

    @if (isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-3">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h5 class="mb-1">Two-Factor Authentication</h5>
                        <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        @if (lastPasswordChange.HasValue)
                        {
                            <small class="text-muted ms-3">
                                Last password change: @lastPasswordChange.Value.ToString("d")
                            </small>
                        }
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@twoFactorEnabled"
                               @onchange="e => twoFactorEnabled = (bool)(e.Value ?? false)" />
                    </div>
                </div>
            </div>
        </div>

        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">Active Sessions</h5>
            </div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session != sessions.FirstOrDefault())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => sessionToRevoke = session">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <RevokeSessionDialog
            Session="@sessionToRevoke"
            OnConfirm="ConfirmRevoke"
            OnCancel="() => sessionToRevoke = null" />
    }
</div>

@code {
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();
    private ActiveSession? sessionToRevoke;
    private bool isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        isLoading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = settings.Sessions;
        isLoading = false;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
        sessions.Remove(sessionToRevoke);
        sessionToRevoke = null;
    }
}
"}

{"path": "/tmp/sv-cc4084934c2743f98203fbf80f935e83/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>

    @if (isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var t in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{t}")" value="@t"
                                   checked="@(theme == t)"
                                   @onchange="() => theme = t" />
                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var fs in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{fs}")" value="@fs"
                                   checked="@(fontSize == fs)"
                                   @onchange="() => fontSize = fs" />
                            <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" @bind="language">
                        <option value="en">English</option>
                        <option value="es">Spanish</option>
                        <option value="fr">French</option>
                        <option value="de">German</option>
                        <option value="ja">Japanese</option>
                        <option value="zh">Chinese</option>
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <div class="col-md-6">
                <h5>Preview</h5>
                <div class="appearance-preview @PreviewThemeClass"
                     style="font-size: @PreviewFontSize; padding: @(compactMode ? "0.5rem" : "1rem");">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <p class="preview-text">
                        This is how your content will look with the selected settings.
                        The theme is <strong>@theme</strong>, font size is <strong>@fontSize</strong>,
                        and compact mode is <strong>@(compactMode ? "on" : "off")</strong>.
                    </p>
                    <div class="preview-actions">
                        <span class="btn btn-sm btn-primary me-1">Action</span>
                        <span class="btn btn-sm btn-outline-secondary">Cancel</span>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(successMessage))
        {
            <div class="alert alert-success alert-dismissible fade show mt-3" role="alert">
                @successMessage
                <button type="button" class="btn-close" @onclick="() => successMessage = null"></button>
            </div>
        }

        <button class="btn btn-primary mt-3" @onclick="SaveAppearance" disabled="@isSaving">
            @if (isSaving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save
        </button>
    }
</div>

@code {
    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool isLoading = true;
    private bool isSaving;
    private string? successMessage;

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    protected override async Task OnInitializedAsync()
    {
        isLoading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        theme = settings.Theme;
        fontSize = settings.FontSize;
        language = settings.Language;
        compactMode = settings.CompactMode;
        isLoading = false;
    }

    private async Task SaveAppearance()
    {
        isSaving = true;
        successMessage = null;
        var settings = new AppearanceSettings(theme, fontSize, language, compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        successMessage = "Appearance settings saved!";
        isSaving = false;
    }
}
"}

