namespace sv_cc4084934c2743f98203fbf80f935e83.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile</h3>

    @if (isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="email" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview">
                    <label class="form-label">Avatar Preview</label>
                    <div class="avatar-frame">
                        @if (!string.IsNullOrWhiteSpace(avatarUrl))
                        {
                            <img src="@avatarUrl" alt="Avatar" class="avatar-image" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">No Avatar</div>
                        }
                    </div>
                    <div class="mt-2">
                        <label class="form-label">Avatar URL</label>
                        <input type="url" class="form-control form-control-sm" @bind="avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(successMessage))
        {
            <div class="alert alert-success alert-dismissible fade show mt-3" role="alert">
                @successMessage
                <button type="button" class="btn-close" @onclick="() => successMessage = null"></button>
            </div>
        }

        <div class="mt-3 d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveChanges" disabled="@isSaving">
                @if (isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    private string displayName = "";
    private string email = "";
    private string bio = "";
    private string avatarUrl = "";
    private UserProfile? savedProfile;
    private bool isLoading = true;
    private bool isSaving;
    private string? successMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        isLoading = true;
        savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(savedProfile);
        isLoading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        bio = profile.Bio;
        avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveChanges()
    {
        isSaving = true;
        successMessage = null;
        var profile = new UserProfile(displayName, email, avatarUrl, bio);
        await SettingsService.SaveProfileAsync(profile);
        savedProfile = profile;
        successMessage = "Profile saved successfully!";
        isSaving = false;
    }

    private void DiscardChanges()
    {
        if (savedProfile is not null)
        {
            ApplyProfile(savedProfile);
        }
        successMessage = null;
    }
}

