@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="sidebar-icon">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notifications</h3>

    @if (isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="mb-4">
            <h5>Notification Channels</h5>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            @if (allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in allChannels)
                {
                    <div class="form-check mb-1">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMuteChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>

        @if (!string.IsNullOrEmpty(successMessage))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @successMessage
                <button type="button" class="btn-close" @onclick="() => successMessage = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SavePreferences" disabled="@isSaving">
            @if (isSaving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();
    private List<string> allChannels = new();
    private bool isLoading = true;
    private bool isSaving;
    private string? successMessage;

    protected override async Task OnInitializedAsync()
    {
        isLoading = true;
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        allChannels = prefs.MutedChannels.Count > 0
            ? prefs.MutedChannels
            : ["general", "announcements", "random", "engineering", "design"];
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        isLoading = false;
    }

    private void ToggleMuteChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        isSaving = true;
        successMessage = null;
        var prefs = new NotificationPrefs(
            emailNotifications, pushNotifications, weeklyDigest,
            mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        successMessage = "Notification preferences saved!";
        isSaving = false;
    }
}

