@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models
@inject ISettingsService SettingsService

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => isExpanded = !isExpanded">
        <span>Change Password</span>
        <span>@(isExpanded ? "▲" : "▼")</span>
    </div>
    @if (isExpanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(errorMessage))
            {
                <div class="alert alert-danger">@errorMessage</div>
            }
            @if (!string.IsNullOrEmpty(successMessage))
            {
                <div class="alert alert-success">@successMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@isUpdating">
                @if (isUpdating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    private bool isExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? errorMessage;
    private string? successMessage;
    private bool isUpdating;

    private async Task UpdatePassword()
    {
        errorMessage = null;
        successMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            errorMessage = "All password fields are required.";
            return;
        }

        if (newPassword != confirmPassword)
        {
            errorMessage = "New password and confirmation do not match.";
            return;
        }

        if (newPassword.Length < 8)
        {
            errorMessage = "New password must be at least 8 characters.";
            return;
        }

        isUpdating = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            successMessage = "Password updated successfully!";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            isUpdating = false;
        }
    }
}

