@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models

@if (Session is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="OnCancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Device</dt>
                        <dd class="col-sm-8">@Session.Device</dd>
                        <dt class="col-sm-4">Location</dt>
                        <dd class="col-sm-8">@Session.Location</dd>
                        <dt class="col-sm-4">Last Active</dt>
                        <dd class="col-sm-8">@Session.LastActive.ToString("g")</dd>
                    </dl>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="OnCancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="OnConfirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }
}

@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security</h3>

    @if (isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-3">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h5 class="mb-1">Two-Factor Authentication</h5>
                        <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                        @if (lastPasswordChange.HasValue)
                        {
                            <small class="text-muted ms-3">
                                Last password change: @lastPasswordChange.Value.ToString("d")
                            </small>
                        }
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@twoFactorEnabled"
                               @onchange="e => twoFactorEnabled = (bool)(e.Value ?? false)" />
                    </div>
                </div>
            </div>
        </div>

        <div class="card">
            <div class="card-header">
                <h5 class="mb-0">Active Sessions</h5>
            </div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session != sessions.FirstOrDefault())
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => sessionToRevoke = session">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <RevokeSessionDialog
            Session="@sessionToRevoke"
            OnConfirm="ConfirmRevoke"
            OnCancel="() => sessionToRevoke = null" />
    }
</div>

@code {
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();
    private ActiveSession? sessionToRevoke;
    private bool isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        isLoading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = settings.Sessions;
        isLoading = false;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
        sessions.Remove(sessionToRevoke);
        sessionToRevoke = null;
    }
}

@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@using sv_cc4084934c2743f98203fbf80f935e83.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>

    @if (isLoading)
    {
        <div class="text-center py-4">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var t in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{t}")" value="@t"
                                   checked="@(theme == t)"
                                   @onchange="() => theme = t" />
                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var fs in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{fs}")" value="@fs"
                                   checked="@(fontSize == fs)"
                                   @onchange="() => fontSize = fs" />
                            <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" @bind="language">
                        <option value="en">English</option>
                        <option value="es">Spanish</option>
                        <option value="fr">French</option>
                        <option value="de">German</option>
                        <option value="ja">Japanese</option>
                        <option value="zh">Chinese</option>
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>
            </div>

            <div class="col-md-6">
                <h5>Preview</h5>
                <div class="appearance-preview @PreviewThemeClass"
                     style="font-size: @PreviewFontSize; padding: @(compactMode ? "0.5rem" : "1rem");">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <p class="preview-text">
                        This is how your content will look with the selected settings.
                        The theme is <strong>@theme</strong>, font size is <strong>@fontSize</strong>,
                        and compact mode is <strong>@(compactMode ? "on" : "off")</strong>.
                    </p>
                    <div class="preview-actions">
                        <span class="btn btn-sm btn-primary me-1">Action</span>
                        <span class="btn btn-sm btn-outline-secondary">Cancel</span>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(successMessage))
        {
            <div class="alert alert-success alert-dismissible fade show mt-3" role="alert">
                @successMessage
                <button type="button" class="btn-close" @onclick="() => successMessage = null"></button>
            </div>
        }

        <button class="btn btn-primary mt-3" @onclick="SaveAppearance" disabled="@isSaving">
            @if (isSaving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save
        </button>
    }
</div>

@code {
    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "en";
    private bool compactMode;
    private bool isLoading = true;
    private bool isSaving;
    private string? successMessage;

    private string PreviewThemeClass => theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    protected override async Task OnInitializedAsync()
    {
        isLoading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        theme = settings.Theme;
        fontSize = settings.FontSize;
        language = settings.Language;
        compactMode = settings.CompactMode;
        isLoading = false;
    }

    private async Task SaveAppearance()
    {
        isSaving = true;
        successMessage = null;
        var settings = new AppearanceSettings(theme, fontSize, language, compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        successMessage = "Appearance settings saved!";
        isSaving = false;
    }
}

@page "/settings"
@namespace sv_cc4084934c2743f98203fbf80f935e83.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@activeSection"
                     OnSectionChanged="section => activeSection = section" />

    <div class="settings-content">
        @switch (activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string activeSection = "profile";
}

.settings-dashboard {
    display: flex;
    min-height: 70vh;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

::deep .settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

::deep .sidebar-title {
    padding: 0 1rem;
    margin-bottom: 0.75rem;
    color: #6c757d;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

::deep .settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
    font-size: 0.95rem;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

::deep .sidebar-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    overflow-y: auto;
}

::deep .settings-section h3 {
    margin-bottom: 1.25rem;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid #e9ecef;
}

::deep .avatar-preview {
    text-align: center;
}

::deep .avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    margin: 0 auto 0.5rem;
    border: 3px solid #dee2e6;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

::deep .avatar-image {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

::deep .avatar-placeholder {
    color: #adb5bd;
    font-size: 0.85rem;
}

::deep .appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    min-height: 160px;
    transition: all 0.2s ease;
}

::deep .preview-light {
    background: #ffffff;
    color: #212529;
}

::deep .preview-dark {
    background: #1a1a2e;
    color: #e0e0e0;
    border-color: #444;
}

::deep .preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1a1a2e 50%);
    color: #212529;
}

::deep .preview-header {
    margin-bottom: 0.5rem;
    padding-bottom: 0.35rem;
    border-bottom: 1px solid currentColor;
    opacity: 0.5;
}

::deep .preview-text {
    margin-bottom: 0.75rem;
    line-height: 1.5;
}

