+
+::deep .preview-dark {
+    background: #1a1a2e;
+    color: #e0e0e0;
+    border-color: #444;
+}
+
+::deep .preview-system {
+    background: linear-gradient(135deg, #ffffff 50%, #1a1a2e 50%);
+    color: #212529;
+}
+
+::deep .preview-header {
+    margin-bottom: 0.5rem;
+    padding-bottom: 0.35rem;
+    border-bottom: 1px solid currentColor;
+    opacity: 0.5;
+}
+
+::deep .preview-text {
+    margin-bottom: 0.75rem;
+    line-height: 1.5;
+}
